#!/usr/bin/env python3
"""
Recipe Converter - Word Document to Modern Recipe Card Format
Updated for Namecheap deployment with main site + momsrecipes subpage

This script reads Microsoft Word documents containing recipes and converts them
into a structured format with:
- Main site landing page
- Mom's recipes on /momsrecipes/ subpage
- Organized folder structure by meal type
- HTML recipe cards for web display
- Searchable web interface
- Word document outputs

All metadata fields included:
- meal_type, main_ingredient, method, cuisine, occasion
- family_source, ingredients, directions, notes, image

Requirements:
- python-docx (pip install python-docx)
- Pillow (pip install Pillow)
- lxml (pip install lxml)

Installation:
    pip install python-docx Pillow lxml

Or use requirements.txt:
    pip install -r requirements.txt

Author: Created for Paul's Family Recipe Preservation Project
"""

import os
import sys
import json
import uuid
from pathlib import Path
from docx import Document
from docx.shared import Pt, Inches, RGBColor
from docx.enum.text import WD_ALIGN_PARAGRAPH
import re
import html


# Embedded Mom's baking background image (base64 encoded JPG, 800px wide, optimized)
# This ensures the blog background is always available without external file dependency
MOM_BAKING_BG_BASE64 = """"""

# Embedded title changes background image (handwritten recipe card)
TITLE_CHANGE_BG_BASE64 = """"""



class RecipeParser:
    """Parses recipes from Word documents"""
    
    def __init__(self):
        self.current_recipe = None
        self.recipes = []
        
    def parse_document(self, doc_path):
        """Parse all recipes from a Word document"""
        doc = Document(doc_path)
        self.recipes = []
        self.current_recipe = None
        self.doc_path = doc_path  # Store for image extraction
        
        in_ingredients = False
        in_instructions = False
        last_empty_line = -999  # Track empty lines as recipe separators
        current_recipe_images = []  # Track images for current recipe
        first_recipe_started = False  # Track if we've found the first recipe yet
        
        for i, para in enumerate(doc.paragraphs):
            text = para.text.strip()
            
            # Check for images in this paragraph
            if para._element.xpath('.//pic:pic'):
                # Found an image - store it for current recipe (avoid duplicates)
                for run in para.runs:
                    if 'graphicData' in run._element.xml:
                        if i not in current_recipe_images:  # Avoid duplicates
                            current_recipe_images.append(i)  # Store paragraph index with image
                        break  # Only count once per paragraph
            
            # Track empty lines as potential recipe separators
            if not text:
                last_empty_line = i
                continue
            
            # Detect recipe title - ONLY Heading 1 paragraphs are considered
            # Everything else (Heading 2, Normal, etc.) is NOT a recipe title
            if para.style and para.style.name == 'Heading 1':
                # Heading 1 is the ONLY indicator of recipe title
                # Only exclude obvious non-recipe patterns:
                text_lower = text.lower()
                
                # Skip document headers (very early + specific keywords)
                if i < 3 and text_lower in ['recipe collection', 'supplementary recipes', 'recipes']:
                    is_title = False
                # Skip attribution lines (From:, Recipe from:, Source:, By)
                elif text_lower.startswith(('from:', 'recipe from:', 'source:', 'from ', 'by ')):
                    is_title = False
                # Skip section headers (Ingredients, Instructions, Notes)
                elif text_lower in ['ingredients:', 'ingredients', 'instructions:', 'instructions',
                                   'directions:', 'directions', 'preparation:', 'preparation',
                                   'method:', 'notes:', 'notes', 'note:']:
                    is_title = False
                # Skip person names that are clearly not recipes
                # Pattern: "X's Mother/Father", "- Mrs.", "- Mr." attribution lines
                elif ("'s mother" in text_lower or "'s father" in text_lower or 
                      " - mrs." in text_lower or " - mr." in text_lower):
                    is_title = False
                # Skip image/page references and metadata
                # Pattern: contains "page", "pictured", "photo", "picture", "cool pictures"
                elif any(keyword in text_lower for keyword in ['pictured on page', 'page ', 'cool pictures', 
                                                                'photos from', 'pictures from', 'see page']):
                    is_title = False
                else:
                    # All other Heading 1s are recipe titles
                    is_title = True
            else:
                # NOT Heading 1 = NOT a recipe title (no heuristic fallback)
                is_title = False
            
            if is_title:
                # Save previous recipe if it exists and has content
                if self.current_recipe and (self.current_recipe['ingredients'] or self.current_recipe['directions']):
                    # Save any images that were found with this recipe
                    if current_recipe_images:
                        self.current_recipe['image_paragraphs'] = current_recipe_images
                    # Set end paragraph for previous recipe
                    self.current_recipe['end_paragraph'] = i - 1
                    self.recipes.append(self.current_recipe)
                
                # If this is the first recipe, clear any images that appeared before it
                if not first_recipe_started:
                    current_recipe_images = []
                    first_recipe_started = True
                
                self.current_recipe = self._create_new_recipe(text)
                # Set start paragraph for new recipe
                self.current_recipe['start_paragraph'] = i
                current_recipe_images = []  # Reset for new recipe
                in_ingredients = False
                in_instructions = False
                
            elif self.current_recipe:
                # Parse source/attribution
                if text.lower().startswith(('recipe from:', 'from:', 'source:', 'from ')):
                    source = re.sub(r'^(recipe from:|from:|source:|from)\s*', '', text, flags=re.IGNORECASE)
                    self.current_recipe['family_source'] = source.strip()
                    
                # Parse servings/yield
                elif re.match(r'^(serves|yield|makes):', text.lower()):
                    self.current_recipe['notes'].append(text)
                    
                # Start of ingredients section
                elif text.lower() in ['ingredients:', 'ingredients']:
                    in_ingredients = True
                    in_instructions = False
                    
                # Start of instructions section
                elif text.lower() in ['instructions:', 'instructions', 'directions:', 'directions',
                                      'preparation:', 'preparation', 'method:', 'method']:
                    in_ingredients = False
                    in_instructions = True
                    
                # Auto-detect transition from ingredients to instructions
                # If we see a numbered list item that looks like an instruction
                elif not in_instructions and re.match(r'^\d+\.\s+[A-Z]', text):
                    # This is likely the start of directions
                    in_ingredients = False
                    in_instructions = True
                    cleaned = re.sub(r'^\d+\.\s*', '', text)
                    self.current_recipe['directions'].append(cleaned)
                
                # Auto-detect ingredients section (if not already in it)
                # Lines that look like ingredients: start with amounts, simple items
                elif not in_ingredients and not in_instructions and self._looks_like_ingredient(text):
                    in_ingredients = True
                    self.current_recipe['ingredients'].append(text)
                    
                # Parse ingredients (only if we're in ingredients section)
                elif in_ingredients:
                    # Stop if we hit a numbered instruction
                    if re.match(r'^\d+\.\s+[A-Z]', text):  # "1. Add" style
                        in_ingredients = False
                        in_instructions = True
                        cleaned = re.sub(r'^\d+\.\s*', '', text)
                        self.current_recipe['directions'].append(cleaned)
                    # Stop if line looks like an action verb (instruction)
                    elif self._looks_like_instruction(text):
                        in_ingredients = False
                        in_instructions = True
                        self.current_recipe['directions'].append(text)
                    else:
                        self.current_recipe['ingredients'].append(text)
                    
                # Parse instructions
                elif in_instructions:
                    # Clean up numbered instructions
                    cleaned = re.sub(r'^\d+\.\s*', '', text)
                    self.current_recipe['directions'].append(cleaned)
                    
                # Other notes (before ingredients section starts)
                # Only add if it's not a stray instruction line
                elif not in_ingredients and not in_instructions:
                    # Skip if it looks like an instruction
                    if not text[0].isdigit() and not text.startswith('"'):
                        self.current_recipe['notes'].append(text)
        
        # Add the last recipe if it has content
        if self.current_recipe and (self.current_recipe['ingredients'] or self.current_recipe['directions']):
            # Save any images that were found with this recipe
            if current_recipe_images:
                self.current_recipe['image_paragraphs'] = current_recipe_images
            # Set end paragraph for last recipe
            self.current_recipe['end_paragraph'] = len(doc.paragraphs) - 1
            self.recipes.append(self.current_recipe)
            
        # Now extract actual image files and save them
        self._extract_images_from_document(doc)
            
        return self.recipes
    
    def _is_recipe_title(self, text, index, paragraphs):
        """Determine if text is a recipe title"""
        # Skip document headers
        if index < 5 and any(keyword in text.lower() for keyword in ['recipe', 'collection', 'supplementary']):
            return False
        
        # Must start with capital letter
        if not text[0].isupper():
            return False
            
        # Skip common false positives
        if text.lower().startswith(('from:', 'source:', 'note:', 'makes:', 'serves:', 'yield:')):
            return False
            
        return True
    
    def _looks_like_ingredient(self, text):
        """Detect if a line looks like an ingredient"""
        # Common ingredient patterns
        ingredient_patterns = [
            r'^\d+\s*(cup|cups|tablespoon|tablespoons|teaspoon|teaspoons|tbsp|tsp|pound|pounds|lb|lbs|ounce|ounces|oz|gram|grams|g|kg|ml|liter)',
            r'^\d+/\d+\s*(cup|cups|tablespoon|tablespoons|teaspoon|teaspoons|tbsp|tsp)',
            r'^\d+\s*\d+/\d+\s*(cup|cups|tablespoon|tablespoons|teaspoon|teaspoons|tbsp|tsp)',
            r'^(a pinch|a dash|pinch|dash|some|few)',
            r'^\d+\s*(small|medium|large|whole)',
            r'^(one|two|three|four|five|six|seven|eight|nine|ten)\s+(cup|tablespoon|teaspoon|pound|ounce)',
        ]
        
        text_lower = text.lower()
        
        # Check patterns
        for pattern in ingredient_patterns:
            if re.match(pattern, text_lower):
                return True
        
        # Check for common ingredient keywords
        ingredient_keywords = [
            'flour', 'sugar', 'salt', 'pepper', 'butter', 'oil', 'eggs', 'egg',
            'milk', 'cream', 'water', 'vanilla', 'baking powder', 'baking soda',
            'yeast', 'cheese', 'chocolate', 'cocoa', 'cinnamon', 'nutmeg'
        ]
        
        # If text starts with a number or fraction, likely an ingredient
        if re.match(r'^[\d/]', text):
            return True
        
        # If contains common ingredient words and is relatively short
        if len(text) < 100:  # Ingredients are usually short
            for keyword in ingredient_keywords:
                if keyword in text_lower:
                    return True
        
        return False
    
    def _looks_like_instruction(self, text):
        """Detect if a line looks like an instruction/direction"""
        # Common instruction starting verbs
        instruction_verbs = [
            'preheat', 'heat', 'cook', 'bake', 'mix', 'stir', 'combine', 'add',
            'pour', 'place', 'put', 'set', 'remove', 'cool', 'chill', 'freeze',
            'blend', 'whisk', 'beat', 'fold', 'knead', 'roll', 'cut', 'chop',
            'slice', 'dice', 'mince', 'grate', 'shred', 'melt', 'boil', 'simmer',
            'fry', 'sauté', 'roast', 'grill', 'broil', 'steam', 'serve', 'garnish',
            'season', 'taste', 'adjust', 'spread', 'layer', 'arrange', 'sprinkle',
            'drain', 'rinse', 'wash', 'dry', 'let', 'allow', 'cover', 'uncover',
            'grease', 'line', 'prepare', 'make', 'form', 'shape'
        ]
        
        text_lower = text.lower()
        
        # Check if starts with instruction verb
        for verb in instruction_verbs:
            if text_lower.startswith(verb + ' ') or text_lower.startswith(verb + ','):
                return True
        
        # Check for numbered instruction pattern
        if re.match(r'^\d+\.\s+', text):
            return True
        
        # Instructions are usually longer than ingredients
        if len(text) > 100:
            return True
        
        return False
    
    def _create_new_recipe(self, title):
        """Create a new recipe structure with auto-detected metadata"""
        # Generate unique UUID for this recipe (permanent ID)
        recipe_uuid = str(uuid.uuid4())
        
        recipe = {
            'uuid': recipe_uuid,  # Permanent unique identifier
            'title': title,
            'meal_type': '',
            'main_ingredient': '',
            'method': '',
            'cuisine': '',
            'occasion': '',
            'family_source': '',
            'ingredients': [],
            'directions': [],
            'notes': [],
            'image': '',
            'image_paragraphs': []
        }
        
        # Auto-detect metadata from title
        self._detect_metadata(recipe, title)
        
        return recipe
    
