    def _generate_favicon(self):
        """Generate favicon.ico file"""
        import struct
        
        # Simple 16x16 pink image
        width, height = 16, 16
        pink = (255, 105, 180)  # RGB for #ff69b4
        
        # BMP data for 16x16 image
        bmp_header_size = 40
        bmp_data_size = width * height * 3  # RGB, 3 bytes per pixel
        
        # Create BMP data
        bmp_data = bytearray()
        
        # BMP info header
        bmp_data.extend(struct.pack('<I', bmp_header_size))  # Header size
        bmp_data.extend(struct.pack('<i', width))             # Width
        bmp_data.extend(struct.pack('<i', height * 2))        # Height (doubled for ICO)
        bmp_data.extend(struct.pack('<H', 1))                 # Planes
        bmp_data.extend(struct.pack('<H', 24))                # Bits per pixel
        bmp_data.extend(struct.pack('<I', 0))                 # Compression
        bmp_data.extend(struct.pack('<I', bmp_data_size))     # Image size
        bmp_data.extend(struct.pack('<i', 0))                 # X pixels per meter
        bmp_data.extend(struct.pack('<i', 0))                 # Y pixels per meter
        bmp_data.extend(struct.pack('<I', 0))                 # Colors used
        bmp_data.extend(struct.pack('<I', 0))                 # Important colors
        
        # Pixel data (bottom-up)
        for y in range(height):
            for x in range(width):
                bmp_data.extend(bytes([pink[2], pink[1], pink[0]]))  # BGR format
        
        # ICO header
        ico_data = bytearray()
        ico_data.extend(struct.pack('<H', 0))      # Reserved
        ico_data.extend(struct.pack('<H', 1))      # Type (1 = ICO)
        ico_data.extend(struct.pack('<H', 1))      # Number of images
        
        # Directory entry
        ico_data.extend(struct.pack('<B', width))  # Width
        ico_data.extend(struct.pack('<B', height)) # Height
        ico_data.extend(struct.pack('<B', 0))      # Color palette
        ico_data.extend(struct.pack('<B', 0))      # Reserved
        ico_data.extend(struct.pack('<H', 1))      # Color planes
        ico_data.extend(struct.pack('<H', 24))     # Bits per pixel
        ico_data.extend(struct.pack('<I', len(bmp_data)))  # Size of image data
        ico_data.extend(struct.pack('<I', 22))     # Offset to image data
        
        # Combine
        ico_data.extend(bmp_data)
        
        # Write to both root and momsrecipes folder
        for location in [self.output_dir, self.output_dir / 'momsrecipes']:
            favicon_path = location / 'favicon.ico'
            with open(favicon_path, 'wb') as f:
                f.write(ico_data)
    
    def _copy_images(self):
        """Copy images from temp directory to website"""
        import shutil
        import base64
        
        # Copy recipe images from temp directory
        temp_dir = Path('temp_images')
        if temp_dir.exists():
            for img_file in temp_dir.glob('*'):
                if img_file.is_file():
                    shutil.copy(img_file, self.images_dir / img_file.name)
        
        # Decode and save embedded Mom baking background image for blog section
        try:
            mom_bg_dest = self.images_dir / 'mom-baking-bg.jpg'
            img_data = base64.b64decode(MOM_BAKING_BG_BASE64)
            with open(str(mom_bg_dest), 'wb') as f:
                f.write(img_data)
            print(f"  ✓ Created blog background: mom-baking-bg.jpg ({len(img_data) // 1024}KB)")
        except Exception as e:
            print(f"  ⚠ Could not create blog background: {e}")
        
        # Decode and save embedded title change background image
        try:
            title_bg_dest = self.images_dir / 'title-change-bg.jpg'
            img_data = base64.b64decode(TITLE_CHANGE_BG_BASE64)
            with open(str(title_bg_dest), 'wb') as f:
                f.write(img_data)
            print(f"  ✓ Created title change background: title-change-bg.jpg ({len(img_data) // 1024}KB)")
        except Exception as e:
            print(f"  ⚠ Could not create title change background: {e}")
    
